// Haversine GPS check sub-workflow
// Input from trigger: { gpsLat, gpsLng, propertyUid }
// Input from sheet:   { latitude, longitude, ... }
const trigger = $('Execute Workflow Trigger').first().json;
const coords  = $input.first().json;

const R = 6371000;
const toRad = deg => deg * (Math.PI / 180);

const gpsLat  = parseFloat(trigger.gpsLat);
const gpsLng  = parseFloat(trigger.gpsLng);
const propLat = parseFloat(coords.latitude);
const propLng = parseFloat(coords.longitude);

if (![gpsLat, gpsLng, propLat, propLng].every(Number.isFinite)) {
  throw new Error(
    `Invalid coordinates — gpsLat:${trigger.gpsLat} gpsLng:${trigger.gpsLng} ` +
    `propLat:${coords.latitude} propLng:${coords.longitude}`
  );
}

const dLat = toRad(propLat - gpsLat);
const dLng = toRad(propLng - gpsLng);
const a = Math.sin(dLat/2)**2 +
          Math.cos(toRad(gpsLat)) * Math.cos(toRad(propLat)) * Math.sin(dLng/2)**2;
const distance = Math.round(R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)));

return [{ json: {
  gpsLat:      trigger.gpsLat,
  gpsLng:      trigger.gpsLng,
  propertyLat: coords.latitude,
  propertyLng: coords.longitude,
  distance,
  withinRadius: distance <= 100
} }];
